  7	import { StorageClusterModel } from '@odf/shared/models';
  8	import {
  9	  ClusterServiceVersionModel,
 10	  InfrastructureModel,
 11	} from '@odf/shared/models';
 12	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
 13	import { getName } from '@odf/shared/selectors';
 14	import { InfrastructureKind, StorageClusterKind } from '@odf/shared/types';
 15	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 16	import { getOprVersionFromCSV } from '@odf/shared/utils';
 17	import {
 18	  getInfrastructurePlatform,
 19	  resourcePathFromModel,
 20	  referenceForModel,
 21	} from '@odf/shared/utils';
 22	import {
 23	  useK8sWatchResource,
 24	  useFlag,
 25	} from '@openshift-console/dynamic-plugin-sdk';
 26	import { Link } from 'react-router-dom-v5-compat';
 27	import {
 28	  Card,
 29	  CardBody,
 30	  CardHeader,
 31	  CardTitle,
 32	  DescriptionList,
 33	} from '@patternfly/react-core';
 34	import { PROVIDER_MODE } from '../../../odf/features';
 35	import EncryptionPopover from '../common/details-card/encryption-popover';
 36	
 37	const storageClusterResource = {
 38	  kind: referenceForModel(StorageClusterModel),
 39	  isList: true,
 40	};
 41	
 42	const DetailsCard: React.FC = () => {
 43	  const { t } = useCustomTranslation();
 44	
 45	  const { odfNamespace, isNsSafe } = useODFNamespaceSelector();
 46	
 47	  const [infrastructure, infrastructureLoaded, infrastructureError] =
 48	    useK8sGet<InfrastructureKind>(InfrastructureModel, DEFAULT_INFRASTRUCTURE);
 49	
 50	  const [ocsData, ocsLoaded, ocsError] = useK8sWatchResource<
 51	    StorageClusterKind[]
 52	  >(storageClusterResource);
 53	
 54	  const [csv, csvLoaded, csvError] = useFetchCsv({
 55	    specName: ODF_OPERATOR,
 56	    namespace: odfNamespace,
 57	    startPollingInstantly: isNsSafe,
 58	  });
 59	
 60	  const infrastructurePlatform = getInfrastructurePlatform(infrastructure);
 61	  const storageCluster: StorageClusterKind = ocsData?.find(
 62	    (sc: StorageClusterKind) => !isExternalCluster(sc)
 63	  );
 64	  const ocsName = getName(storageCluster);
 65	
 66	  const isProviderMode = useFlag(PROVIDER_MODE);
 67	
 68	  const serviceVersion = getOprVersionFromCSV(csv);
 69	  const servicePath = `${resourcePathFromModel(
 70	    ClusterServiceVersionModel,
 71	    getName(csv),
 72	    odfNamespace
 73	  )}`;
 74	  const serviceName = t('Data Foundation');
 75	
 76	  return (
 77	    <Card>
 78	      <CardHeader>
 79	        <CardTitle>{t('Details')}</CardTitle>
 80	      </CardHeader>
 81	      <CardBody>
 82	        <DescriptionList>
 83	          <DetailItem key="service_name" title={t('Service name')}>
 84	            {isNsSafe && csvLoaded && !csvError ? (
 85	              <Link data-test="ocs-link" to={servicePath}>
 86	                {serviceName}
 87	              </Link>
 88	            ) : (
 89	              serviceName
 90	            )}
 91	          </DetailItem>
 92	          <DetailItem
 93	            key="cluster_name"
 94	            title={t('Cluster name')}
 95	            error={ocsError as any}
 96	            isLoading={!ocsLoaded}
 97	          >
 98	            {ocsName}
 99	          </DetailItem>
100	          <DetailItem
101	            key="provider"
102	            title={t('Provider')}
103	            error={infrastructureError}
104	            isLoading={!infrastructureLoaded}
105	          >
106	            {infrastructurePlatform}
107	          </DetailItem>
108	          <DetailItem title={t('Mode')}>
109	            {isProviderMode ? t('Provider') : t('Internal')}
110	          </DetailItem>
111	          <DetailItem
112	            key="version"
113	            title={t('Version')}
114	            isLoading={!csvLoaded}
115	            error={csvError}
116	          >
117	            {serviceVersion}
118	          </DetailItem>
119	          <DetailItem
120	            key="encryption"
121	            title={t('Encryption')}
122	            isLoading={!ocsLoaded}
123	            error={ocsError}
124	          >
125	            <EncryptionPopover
126	              cluster={storageCluster}
127	              isObjectDashboard={false}
128	            />
129	          </DetailItem>
130	        </DescriptionList>
131	      </CardBody>
132	    </Card>
133	  );
134	};
135	
136	export default DetailsCard;

